import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limit the buffer size to prevent buffer overflow
        char[] buffer = new char[Math.min(input.length(), 10)];

        // Copy only up to the length of the buffer
        input.getChars(0, buffer.length, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
